    preSnap:["Load the box — six on the line plus the strong safety is the point","Sub out the instant he shows empty or four wide","Corners are on an island; press only if you must","Add an inside linebacker on short yardage for the extra hat"],
    coaching:[{label:"Coverage Shell",value:"Cov 3"},{label:"Gap Integrity",value:"Aggressive"},{label:"CB Depth",value:"7 yds"},{label:"Coverage Strategy",value:"Balanced"},{label:"Usage",value:"Run downs / power"}],
