    preSnap:["Keep the stacked backers hidden — the center must not locate both","Run the Snake and Crash stunts through the unblocked gaps","Corners: Cushion vs shots, Press vs quick game","Assign the contain edge when the quarterback is a run threat"],
    coaching:[{label:"Coverage Shell",value:"Cov 3"},{label:"CB Depth",value:"7 yds"},{label:"Gap Integrity",value:"Balanced"},{label:"Coverage Strategy",value:"Balanced"},{label:"Usage",value:"11/12 personnel / stacked pressure"}],
    callsheet:[{down:"1st & 10",call:"3-4 Over Ed · Cover 3 Sky",note:"Base call behind the stack"},{down:"2nd & Medium",call:"3-4 Over Ed · Strong Snake 3",note:"Twist the stacked backers through"},{down:"3rd & Medium (mobile QB)",call:"3-4 Over Ed · Cover 1 QB Contain",note:"Man with an edge on contain"},{down:"3rd & Long (shots)",call:"3-4 Over Ed · Cover 4 Quarters",note:"Cap the verticals"}],
