    preSnap:["Trust the wall inside — the front handles interior zone","Manufacture the rush with Saw stunts; four man alone is weak","Corners: Cushion vs shots, Press vs quick game","Stunt a linebacker to the edge if the quarterback pulls and runs"],
    coaching:[{label:"Coverage Shell",value:"Cov 3"},{label:"CB Depth",value:"7 yds"},{label:"Gap Integrity",value:"Balanced"},{label:"Coverage Strategy",value:"Balanced"},{label:"Usage",value:"vs spread run / coverage"}],
