    coreTags:["deep_shots","pass_heavy_3rd","two_minute_pass","four_wide","empty","seam_routes"],
    suppTags:["trips","slot_threat","hurry_up","back_shoulder"],
    coverages:[
      {name:"Cover 4 Quarters",rating:5,tag:"Base",detail:"Four deep with match rules. The core of the three-high shell, taking away every vertical while the corners two-read the routes."},
      {name:"Cover 6",rating:4,tag:"vs Trips",detail:"Quarter-quarter-half against a trips set. Quarters to the trips side, half to the single side, all from the deep look."},
      {name:"Cover 4 Palms",rating:4,tag:"Deep Shots",detail:"Quarters with a palms two-read. The corners trap the out and rob the shot when he takes it downfield."},
      {name:"Tampa 2 Spy",rating:4,tag:"vs Mobile QB",detail:"Two deep with a linebacker on the pole and a spy on the quarterback. The mobile-quarterback answer from the coverage shell."},
      {name:"3 Double Cloud",rating:3,tag:"vs Quick Game",detail:"Three deep with the corners rolled to cloud flats. Takes away the quick perimeter throw from the deep look."},
      {name:"Edge Blitz 3",rating:3,tag:"Zone Pressure",detail:"Five-man edge fire zone with three deep. The rare pressure when you want to surprise a passer sitting on your coverage."},
    ],
    preSnap:["Stay in it only on obvious passing downs — the run will hurt you","Disguise the rotation; three-high can become anything","Corners: two-read the routes, Press only vs quick game","Tampa 2 Spy the moment the passer wants to escape"],
    coaching:[{label:"Coverage Shell",value:"Cov 4"},{label:"Safety Depth",value:"12"},{label:"CB Depth",value:"7 yds"},{label:"Coverage Strategy",value:"Conservative"},{label:"Usage",value:"Passing downs / deep-ball defense"}],
