    preSnap:["Keep the three-high help — this is still a passing-down front","Slant the front to twist pressure behind the shell","Corners: two-read the routes, Press only vs quick game","Show the deep look, then bring the slant blitz"],
    coaching:[{label:"Coverage Shell",value:"Cov 4"},{label:"Safety Depth",value:"12"},{label:"CB Depth",value:"7 yds"},{label:"Coverage Strategy",value:"Balanced"},{label:"Usage",value:"Passing downs / disguised pressure"}],
