    callsheet:[{down:"1st & 10 (spread)",call:"3-3-5 Split · Cover 3 Match",note:"Match the routes, keep the threat"},{down:"2nd & Long",call:"3-3-5 Split · Fire Zone 3",note:"Five come with a three-deep net"},{down:"3rd & Medium",call:"3-3-5 Split · Double Edge Blitz",note:"Both edges, isolate the tackles"},{down:"3rd & Long (must-stop)",call:"3-3-5 Split · Inside Blitz",note:"All-out, ball out or sack"}],
